def load_large_file(filename):
    with open(filename, 'r') as f:
        lines = f.readlines()
    return lines

def process_data(filename):
    data = load_large_file(filename)
    results = []
    for line in data:
        results.append(line.strip().upper())
    return results

def find_matches(filename, pattern):
    data = load_large_file(filename)
    matches = []
    for line in data:
        if pattern in line:
            matches.append(line)
    return matches

