class Counter:
    def __init__(self):
        self.value = 0

    def increment(self):
        current = self.value
        current += 1
        self.value = current

    def get(self):
        return self.value

class Cache:
    _instance = None
    _data = {}

    @classmethod
    def get_instance(cls):
        if cls._instance is None:
            cls._instance = cls()
        return cls._instance

    def set(self, key, value):
        self._data[key] = value

    def get(self, key):
        return self._data.get(key)

